function GaleriaTour() {
  const [current, setCurrent] = useState(0);
  const [playing, setPlaying] = useState(true);
  const [animating, setAnimating] = useState(false);

  const goTo = (idx) => {
    if (animating) return;
    setAnimating(true);
    setTimeout(() => {
      setCurrent(idx);
      setAnimating(false);
    }, 350);
  };

  const next = () => goTo((current + 1) % tourScenes.length);
  const prev = () => goTo((current - 1 + tourScenes.length) % tourScenes.length);

  // Auto-advance
  useState(() => {
    const interval = setInterval(() => {
      if (playing) {
        setAnimating(true);
        setTimeout(() => {
          setCurrent(c => (c + 1) % tourScenes.length);
          setAnimating(false);
        }, 350);
      }
    }, 3200);
    return () => clearInterval(interval);
  }, [playing]);

  const scene = tourScenes[current];

  return (
    <div style={{ paddingTop: 16 }}>
      {/* Header */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
        <div>
          <h2 style={{ fontFamily: "'Fredoka One', cursive", color: COLORS.dark, fontSize: 22, margin: 0 }}>🎬 Tour pelo Espaço</h2>
          <p style={{ color: COLORS.muted, fontSize: 12, fontFamily: "'Nunito', sans-serif", margin: "2px 0 0" }}>Conheça cada cantinho do Espaço Kids</p>
        </div>
        <button onClick={() => setPlaying(p => !p)} style={{
          background: playing ? COLORS.primary + "22" : COLORS.bg,
          border: `2px solid ${playing ? COLORS.primary : COLORS.muted}`,
          borderRadius: 20, padding: "6px 14px", cursor: "pointer",
          fontFamily: "'Nunito', sans-serif", fontWeight: 800,
          color: playing ? COLORS.primary : COLORS.muted, fontSize: 12,
        }}>
          {playing ? "⏸ Pausar" : "▶ Play"}
        </button>
      </div>

      {/* Main cinematic card */}
      <div style={{
        borderRadius: 28, overflow: "hidden",
        boxShadow: "0 20px 60px rgba(124,58,237,0.25)",
        marginBottom: 14, position: "relative",
        transition: "opacity 0.35s ease",
        opacity: animating ? 0 : 1,
      }}>
        {/* Real photo scene */}
        <div style={{
          height: 280, position: "relative", overflow: "hidden",
        }}>
          {/* Real photo */}
          <img src={scene.img} alt={scene.title} style={{
            width: "100%", height: "100%", objectFit: "cover",
            display: "block",
          }} />
          {/* Gradient overlay for text readability */}
          <div style={{
            position: "absolute", inset: 0,
            background: "linear-gradient(to bottom, rgba(0,0,0,0.25) 0%, rgba(0,0,0,0.0) 40%, rgba(0,0,0,0.55) 100%)",
          }} />

          {/* Tag */}
          <div style={{
            position: "absolute", top: 16, left: 16,
            background: "rgba(255,255,255,0.22)", backdropFilter: "blur(8px)",
            borderRadius: 20, padding: "4px 14px",
            fontFamily: "'Nunito', sans-serif", fontWeight: 800,
            color: "white", fontSize: 11, letterSpacing: 1,
          }}>
            ✦ {scene.tag.toUpperCase()}
          </div>

          {/* Scene counter */}
          <div style={{
            position: "absolute", top: 16, right: 16,
            background: "rgba(0,0,0,0.35)", borderRadius: 20, padding: "4px 12px",
            fontFamily: "'Nunito', sans-serif", fontWeight: 800,
            color: "white", fontSize: 11,
          }}>
            {current + 1} / {tourScenes.length}
          </div>

          {/* Title on photo */}
          <h3 style={{
            position: "absolute", bottom: 16, left: 16, right: 16,
            fontFamily: "'Fredoka One', cursive", color: "white",
            fontSize: 22, margin: 0, textShadow: "0 2px 12px rgba(0,0,0,0.6)",
          }}>
            {scene.title}
          </h3>
        </div>

        {/* Description card */}
        <div style={{ background: "white", padding: "18px 20px" }}>
          <p style={{
            fontFamily: "'Nunito', sans-serif", color: COLORS.text,
            fontSize: 14, lineHeight: 1.6, margin: "0 0 14px",
          }}>
            {scene.desc}
          </p>

          {/* Progress bar */}
          <div style={{ background: COLORS.bg, borderRadius: 10, height: 4, overflow: "hidden", marginBottom: 14 }}>
            <div style={{
              height: "100%", borderRadius: 10,
              background: `linear-gradient(90deg, ${scene.color1}, ${scene.color2})`,
              width: `${((current + 1) / tourScenes.length) * 100}%`,
              transition: "width 0.4s ease",
            }} />
          </div>

          {/* Navigation */}
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <button onClick={prev} style={{
              background: COLORS.bg, border: "none", borderRadius: 14,
              padding: "10px 18px", cursor: "pointer",
              fontFamily: "'Nunito', sans-serif", fontWeight: 800,
              color: COLORS.dark, fontSize: 14,
            }}>
              ← Anterior
            </button>
            <div style={{ display: "flex", gap: 6 }}>
              {tourScenes.map((_, i) => (
                <div key={i} onClick={() => goTo(i)} style={{
                  width: i === current ? 20 : 8, height: 8,
                  borderRadius: 4, cursor: "pointer",
                  background: i === current
                    ? `linear-gradient(90deg, ${scene.color1}, ${scene.color2})`
                    : COLORS.bg,
                  transition: "all 0.3s ease",
                }} />
              ))}
            </div>
            <button onClick={next} style={{
              background: `linear-gradient(135deg, ${scene.color1}, ${scene.color2})`,
              border: "none", borderRadius: 14,
              padding: "10px 18px", cursor: "pointer",
              fontFamily: "'Nunito', sans-serif", fontWeight: 800,
              color: "white", fontSize: 14,
            }}>
              Próximo →
            </button>
          </div>
        </div>
      </div>

      {/* Thumbnail strip */}
      <div style={{ display: "flex", gap: 8, overflowX: "auto", paddingBottom: 4, marginBottom: 14 }}>
        {tourScenes.map((s, i) => (
          <div key={s.id} onClick={() => goTo(i)} style={{
            flexShrink: 0, width: 60, height: 60,
            borderRadius: 14, cursor: "pointer", overflow: "hidden",
            border: i === current ? `3px solid ${COLORS.dark}` : "3px solid transparent",
            transition: "all 0.2s ease",
            boxShadow: i === current ? "0 4px 12px rgba(0,0,0,0.25)" : "none",
          }}>
            <img src={s.img} alt={s.title} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
          </div>
        ))}
      </div>

      {/* CTA */}
      <div style={{ background: "white", borderRadius: 20, padding: 16, textAlign: "center", boxShadow: "0 4px 20px rgba(0,0,0,0.06)" }}>
        <p style={{ fontFamily: "'Nunito', sans-serif", color: COLORS.muted, fontSize: 13, margin: "0 0 10px" }}>
          Quer conhecer o espaço pessoalmente? 👀
        </p>
        <button onClick={() => window.open('https://wa.me/5548998032906', '_blank')} style={{
          background: `linear-gradient(135deg, ${COLORS.teal}, ${COLORS.accent})`,
          border: "none", borderRadius: 14, padding: "12px 24px",
          color: "white", fontFamily: "'Nunito', sans-serif",
          fontWeight: 800, fontSize: 14, cursor: "pointer",
        }}>
          📞 Fale conosco
        </button>
      </div>
    </div>
  );
}

