  const handleReserva = () => {
    if (!form.nombre || !form.fecha || !form.hora || !form.paquete) return;

    const pkg = packages.find(p => p.name === form.paquete);
    const fechaObj = new Date(form.fecha + 'T12:00:00');
    const diaSemana = fechaObj.getDay(); // 0=dom, 6=sab
    const fimDeSemana = diaSemana === 0 || diaSemana === 6;
    const preco = pkg ? (fimDeSemana ? pkg.priceWeekend : pkg.priceWeek) : 0;
    const sinal = preco / 2;

    const diasNomes = ['Domingo','Segunda','Terça','Quarta','Quinta','Sexta','Sábado'];
    const diaNome = diasNomes[diaSemana];
    const [ano, mes, dia] = form.fecha.split('-');
    const dataFormatada = `${dia}/${mes}/${ano}`;

    const msg = 
`Olá! Gostaria de reservar uma festa no Espaço Kids 🎉

👤 Nome: ${form.nombre}
📱 WhatsApp: ${form.telefono || 'não informado'}
📅 Data: ${dataFormatada} (${diaNome})
🕐 Horário: ${form.hora}hs
🎁 Pacote: ${form.paquete}
👧 Crianças: ${form.chicos || 'não informado'}

💰 Valor total: R$ ${preco}
✅ Sinal para confirmar (50%): R$ ${sinal}

Aguardo confirmação e os dados para pagamento da sinal. Obrigado(a)!`;

    const numero = '5548998032906';
    const url = `https://wa.me/${numero}?text=${encodeURIComponent(msg)}`;
    window.open(url, '_blank');
    setSent(true);
    setForm({ nombre: "", telefono: "", fecha: "", hora: "", paquete: "", chicos: "" });
  };

